create extension if not exists pgcrypto;
create table allowed_domains (id uuid primary key default gen_random_uuid(), domain text unique not null, description text, status text default 'active', created_at timestamptz default now());
create table departments (id uuid primary key default gen_random_uuid(), department_name text unique not null, status text default 'active', created_at timestamptz default now());
create table countries (id uuid primary key default gen_random_uuid(), country_name text not null, country_code text, status text default 'active');
create table branches (id uuid primary key default gen_random_uuid(), branch_name text not null, country_id uuid references countries(id), region text, status text default 'active');
create table app_users (id uuid primary key default gen_random_uuid(), full_name text not null, email text unique not null, mobile text, role text default 'user', department_id uuid references departments(id), branch_id uuid references branches(id), country_id uuid references countries(id), status text default 'pending', email_verified_at timestamptz, created_at timestamptz default now(), updated_at timestamptz default now());
create table portal_categories (id uuid primary key default gen_random_uuid(), category_name text unique not null, description text, icon text, display_order integer default 0, status text default 'active');
create table portals (id uuid primary key default gen_random_uuid(), portal_name text not null, portal_slug text unique not null, portal_url text not null, short_description text, full_description text, category_id uuid references portal_categories(id), department_id uuid references departments(id), logo_url text, banner_url text, business_owner text, technical_owner text, support_email text, support_phone text, status text default 'live', visibility text default 'logged_in', go_live_date date, version text, ai_enabled boolean default false, created_by uuid references app_users(id), created_at timestamptz default now(), updated_at timestamptz default now());
create table portal_documents (id uuid primary key default gen_random_uuid(), portal_id uuid references portals(id) on delete cascade, document_title text not null, document_url text, document_type text, version text, visibility text default 'logged_in', uploaded_by uuid references app_users(id), uploaded_at timestamptz default now(), status text default 'active', extracted_text text, ai_enabled boolean default false, tags text[]);
create table portal_faqs (id uuid primary key default gen_random_uuid(), portal_id uuid references portals(id) on delete cascade, question text not null, answer text not null, visibility text default 'logged_in', status text default 'active', created_by uuid references app_users(id), created_at timestamptz default now(), updated_at timestamptz default now());
create table favorites (id uuid primary key default gen_random_uuid(), user_id uuid not null references app_users(id) on delete cascade, portal_id uuid references portals(id) on delete cascade, display_order integer default 0, created_at timestamptz default now(), unique(user_id, portal_id));
create table support_tickets (id uuid primary key default gen_random_uuid(), ticket_number text unique, user_id uuid references app_users(id), portal_id uuid references portals(id), category text not null, priority text default 'medium', subject text not null, description text not null, attachment_url text, status text default 'submitted', assigned_to uuid references app_users(id), created_at timestamptz default now(), updated_at timestamptz default now(), resolved_at timestamptz);
create table portal_access (id uuid primary key default gen_random_uuid(), user_id uuid not null references app_users(id), portal_id uuid references portals(id), access_status text default 'allowed', requested_at timestamptz, approved_by uuid references app_users(id), approved_at timestamptz, remarks text);
create table announcements (id uuid primary key default gen_random_uuid(), title text not null, message text not null, target_audience text default 'all', priority text default 'normal', start_date date, end_date date, status text default 'active', created_by uuid references app_users(id), created_at timestamptz default now());
create table audit_logs (id uuid primary key default gen_random_uuid(), activity_type text not null, performed_by uuid references app_users(id), affected_user_id uuid references app_users(id), affected_portal_id uuid references portals(id), metadata jsonb default '{}'::jsonb, created_at timestamptz default now());
